package org.jsoup.parser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.parser.Parser;
import org.jsoup.safety.Whitelist;
import static org.junit.Assert.*;

public class StepDefs {

    private String htmlString;
    private Document document;
    private long startTime;
    private Exception parsingException;

    @Given("a large HTML string with {int} nested \"<dl><dd>\" pairs")
    public void a_large_HTML_string_with_nested_dl_dd_pairs(int count) {
        StringBuilder html = new StringBuilder();
        html.append("<html><body>");

        for (int i = 0; i < count; i++) {
            html.append("<dl><dd>nested content ").append(i).append("</dd></dl>");
        }

        html.append("</body></html>");
        this.htmlString = html.toString();
    }

    @When("the HTML is parsed")
    public void the_HTML_is_parsed() {
        startTime = System.currentTimeMillis();
        try {
            this.document = Jsoup.parse(htmlString);
        } catch (Exception e) {
            this.parsingException = e;
        }
    }

    @Then("the parsing should complete within {int} second")
    public void the_parsing_should_complete_within_second(int seconds) {
        long duration = System.currentTimeMillis() - startTime;
        assertTrue("Parsing took too long: " + duration + "ms", duration < seconds * 1000);
    }

    @Then("the resulting document body should have {int} child nodes")
    public void the_resulting_document_body_should_have_child_nodes(int childCount) {
        if (parsingException != null) {
            throw new RuntimeException("Parsing failed with exception: " + parsingException.getMessage(), parsingException);
        }

        int actualChildCount = document.body().childNodeSize();
        assertEquals(childCount, actualChildCount);
    }

    @Then("the document should contain {int} \"dd\" elements")
    public void the_document_should_contain_dd_elements(int ddCount) {
        if (parsingException != null) {
            throw new RuntimeException("Parsing failed with exception: " + parsingException.getMessage(), parsingException);
        }

        int actualDdCount = document.select("dd").size();
        assertEquals(ddCount, actualDdCount);
    }
}

